window.ERAS = [{"key":"medieval","name":"Medieval / 中世纪","years":"约 1150–1400","keywords":"素歌 · 复调初生 · 修道院","desc":"西方古典音乐的源头。单声的格里高利圣咏在修道院回响，随后奥尔加农让第二条声部升起——复调由此诞生。希尔德加德的通神歌咏、佩罗坦的巴黎圣母院乐派，是这段幽深岁月里最亮的光。"},{"key":"renaissance","name":"Renaissance / 文艺复兴","years":"约 1400–1600","keywords":"无伴奏合唱 · 对位 · 弥撒经文歌","desc":"人声复调的黄金时代。若斯坎、帕勒斯特里那、塔利斯把多条声部编织成澄澈交融的织体，宗教改革与反宗教改革在弥撒与经文歌里角力，四十声部的《Spem in Alium》是纯人声所能抵达的奇迹。"},{"key":"baroque","name":"Baroque / 巴洛克","years":"1600–1750","keywords":"通奏低音 · 赋格 · 协奏曲 · 歌剧诞生","desc":"从蒙特威尔第的第一部歌剧到巴赫的赋格宇宙。数字低音撑起华丽的装饰旋律，维瓦尔第定型协奏曲，亨德尔征服伦敦歌剧院，而巴赫把这一切技法推向前无古人、后无来者的完满。"},{"key":"classical","name":"Classical / 古典主义","years":"约 1730–1820","keywords":"奏鸣曲式 · 均衡 · 交响曲成型","desc":"理性、均衡与清晰的时代。海顿确立交响曲与弦乐四重奏的范式，莫扎特让旋律臻于天然的完美，贝多芬则从这里出发，用意志把古典的框架撑向浪漫的门槛。"},{"key":"romantic","name":"Romantic / 浪漫主义","years":"约 1800–1910","keywords":"个人情感 · 标题音乐 · 歌剧巨制 · 交响诗","desc":"音乐成为自我的告白。舒伯特的艺术歌曲、肖邦的夜曲、瓦格纳的乐剧、柴科夫斯基的绝望、马勒的宇宙——形式不断膨胀，情感不断加压，直到晚期浪漫在辉煌中走向裂变。"},{"key":"modern","name":"Modern / 现代","years":"约 1900–1975","keywords":"调性瓦解 · 节奏革命 · 新语言","desc":"二十世纪把一切推倒重来。德彪西模糊调性，斯特拉文斯基的《春之祭》引发暴动，勋伯格发明十二音，巴托克、肖斯塔科维奇、布里顿在战争与极权的阴影下，为古典音乐找到全新的骨骼与良心。"},{"key":"contemporary","name":"Contemporary / 当代","years":"约 1975–今","keywords":"简约主义 · 神圣极简 · 跨界","desc":"在先锋的极端之后，音乐重新伸手拥抱听众。赖希与格拉斯的简约脉动、佩尔特与戈雷茨基的神圣静默、约翰·亚当斯的新浪漫,让当代古典既能进音乐厅，也能进电影院与流行榜。"}];
window.MOODS = ["夜晚","沉思","激昂","疗愈","庄严","悲伤","喜悦","专注","壮丽","亲密"];
